import org.owasp.esapi.ESAPI;
import org.owasp.esapi.codecs.HTMLEntityCodec;

public class XSSFixedCode {
    public static void main(String[] args) {
        // Simulating user input being received from a form
        String userInput = "<script>alert('XSS Vulnerability!')</script>";

        // Properly handling user input by escaping special characters
        HTMLEntityCodec codec = new HTMLEntityCodec();
        String safeUserInput = codec.encodeForHTML(userInput);

        // Outputting the sanitized user input to the webpage
        System.out.println("Welcome, " + safeUserInput);
    }
}

### Explanation:
취약유형: Cross-Site Scripting (XSS)
